class Solution(object):
    def findAllConcatenatedWordsInADict(self, words):
        word_set = set(words)
        memo = {}

        def is_concat(word):
            if word in memo:
                return memo[word]

            for i in range(1, len(word)):
                left = word[:i]
                right = word[i:]

                if left in word_set:
                    if right in word_set or is_concat(right):
                        memo[word] = True
                        return True

            memo[word] = False
            return False

        return [w for w in words if is_concat(w)]
